     1|/**
     2| * IVX crash-safe task orchestrator.
     3| *
     4| * Receives a large owner task, copies it EXACTLY, splits it into ordered blocks,
     5| * then executes the blocks ONE AT A TIME — persisting each block's result before
     6| * the next starts. This makes large senior-developer tasks crash-safe:
     7| *
     8| *   - A crash/reload/timeout loses at most the single in-flight block.
     9| *   - `resumeTask` continues from the last unfinished block (durable cursor) —
    10| *     never restarting from zero, never re-running completed blocks, never
    11| *     losing the original owner task.
    12| *   - Non-destructive blocks execute without an approval prompt; only the six
    13| *     guarded categories (delete data / prod schema / secrets / billing /
    14| *     security / external access) are marked BLOCKED for explicit confirmation.
    15| *   - After every block finishes, a final review aggregates the proof.
    16| *
    17| * The block executor is injectable so the engine is unit-testable without the AI
    18| * gateway / network / git. The default executor delegates non-destructive work to
    19| * the senior-developer runtime in `systemMode`.
    20| */
    21|import { readFile } from 'node:fs/promises';
    22|import path from 'node:path';
    23|import { classifyOwnerExecutionCommand } from './ivx-owner-execution-mode';
    24|import { splitTaskIntoBlocks } from './ivx-task-block-splitter';
    25|import {
    26|  appendTaskEvent,
    27|  createTask,
    28|  findResumeBlock,
    29|  getTask,
    30|  getTaskBlocks,
    31|  updateTask,
    32|  updateTaskBlock,
    33|  type IVXBlockVerification,
    34|  type IVXTaskBlock,
    35|  type IVXTaskBlockStatus,
    36|  type IVXTaskRecord,
    37|} from './ivx-task-state-store';
    38|
    39|/** Result a block executor returns; mapped onto the durable block record. */
    40|export type IVXBlockExecutionResult = {
    41|  status: IVXTaskBlockStatus;
    42|  codeChanges?: string | null;
    43|  codeDiff?: string | null;
    44|  validationCommand?: string | null;
    45|  testResult?: string | null;
    46|  commitHash?: string | null;
    47|  deploymentStatus?: string | null;
    48|  verification?: IVXBlockVerification | null;
    49|  filesInvolved?: string[];
    50|  blocker?: string | null;
    51|  error?: string | null;
    52|};
    53|
    54|export type IVXBlockExecutor = (
    55|  block: IVXTaskBlock,
    56|  task: IVXTaskRecord,
    57|) => Promise<IVXBlockExecutionResult>;
    58|
    59|/** Hard caps so a runaway/never-completing loop can't spin forever. */
    60|const MAX_RECOVERIES = 10;
    61|const MAX_ATTEMPTS_PER_BLOCK = 2;
    62|
    63|/** Tracks tasks currently being driven in this process to avoid double-running. */
    64|const activeRuns = new Set<string>();
    65|
    66|/**
    67| * Default executor: classify the block, gate destructive work, otherwise run the
    68| * senior-developer runtime end-to-end in systemMode. Dynamically imports the heavy
    69| * runtime so the read-only orchestration paths stay lightweight.
    70| */
    71|export const defaultBlockExecutor: IVXBlockExecutor = async (block) => {
    72|  const decision = classifyOwnerExecutionCommand(block.goal);
    73|  if (decision.requiresApproval) {
    74|    return {
    75|      status: 'BLOCKED',
    76|      blocker: `Requires explicit owner approval — ${decision.reason}`,
    77|    };
    78|  }
    79|
    80|  try {
    81|    const { runIVXSeniorDeveloperTask } = await import('./ivx-senior-developer-runtime');
    82|    const proof = await runIVXSeniorDeveloperTask({
    83|      goal: block.goal,
    84|      systemMode: true,
    85|      approvePatch: true,
    86|      approveGitDeploy: true,
    87|    });
    88|
    89|    const validation = proof.validations.find((entry) => entry.command) ?? proof.validations[0] ?? null;
    90|    const validationPassed = proof.validations.length > 0 && proof.validations.every((entry) => entry.ok);
    91|    const commitSha = proof.gitDeployOperator.github.commitSha;
    92|    const committed = proof.gitDeployOperator.status === 'executed' && Boolean(commitSha);
    93|    const deployed = proof.gitDeployOperator.status === 'executed' && proof.gitDeployOperator.render.deployAttempted;
    94|    const verified = proof.productionVerification.ok;
    95|
    96|    // Capture the real post-deploy verification evidence (endpoint + HTTP status +
    97|    // changed-route check) so the monitor can prove the live app responded — not
    98|    // just show a "verified" word. Only attach it once a deploy actually happened.
    99|    const verification: IVXBlockVerification | null = deployed
   100|      ? {
   101|          endpoint: proof.productionVerification.endpoint,
   102|          ok: proof.productionVerification.ok,
   103|          httpStatus: proof.productionVerification.httpStatus,
   104|          changedRouteOk: proof.changedRouteVerification.ok,
   105|          verifiedAt: new Date().toISOString(),
   106|        }
   107|      : null;
   108|
   109|    let status: IVXTaskBlockStatus = 'COMPLETED';
   110|    if (verified) {
   111|      status = 'VERIFIED';
   112|    } else if (deployed) {
   113|      status = 'DEPLOYED';
   114|    } else if (!proof.ok) {
   115|      status = 'FAILED';
   116|    }
   117|
   118|    // Surface the real reason a block did not complete (failing validation
   119|    // detail, then the git/deploy operator reason) so the owner sees the exact
   120|    // blocker in the task API instead of a generic message.
   121|    // Real code the block wrote, for the live coding stream: prefer the applied
   122|    // unified diff, then any generated-feature source file, so the monitor animates
   123|    // the actual characters IVX produced — not a placeholder.
   124|    const diffText = proof.patchProposal.diffPreview && proof.patchProposal.status === 'proposed'
   125|      ? proof.patchProposal.diffPreview
   126|      : null;
   127|    const generatedSource = await readGeneratedFeatureSource(proof.generatedFeature.feature?.sourceFile ?? null);
   128|    const codeDiff = [diffText, generatedSource].filter((part): part is string => Boolean(part && part.trim())).join('\n\n') || null;
   129|
   130|    const failingValidation = proof.validations.find((entry) => !entry.ok) ?? null;
   131|    const realBlocker = proof.ok
   132|      ? null
   133|      : (failingValidation?.error
   134|        ?? failingValidation?.stderrTail
   135|        ?? proof.gitDeployOperator.reason
   136|        ?? 'Senior-developer runtime reported the block did not complete end-to-end.');
   137|
   138|    return {
   139|      status,
   140|      codeChanges: proof.changedFiles.length > 0 ? proof.changedFiles.join(', ') : 'No code change required (target already satisfies the goal).',
   141|      codeDiff,
   142|      filesInvolved: proof.changedFiles,
   143|      validationCommand: validation?.command ?? null,
   144|      testResult: proof.validations.length > 0 ? `${validationPassed ? 'passed' : 'failed'} (${proof.validations.length} validation${proof.validations.length === 1 ? '' : 's'})` : null,
   145|      commitHash: committed ? commitSha ?? null : null,
   146|      deploymentStatus: deployed ? 'triggered' : 'not-deployed',
   147|      verification,
   148|      blocker: realBlocker,
   149|    };
   150|  } catch (error) {
   151|    const message = error instanceof Error ? error.message : 'Block execution failed.';
   152|    return { status: 'FAILED', error: message, blocker: message };
   153|  }
   154|};
   155|
   156|/**
   157| * Read the source of a generated feature file so the live coding stream can show
   158| * the real characters written. Stays inside the repo, caps size, and never throws.
   159| */
   160|async function readGeneratedFeatureSource(sourceFile: string | null): Promise<string | null> {
   161|  if (!sourceFile || typeof sourceFile !== 'string') {
   162|    return null;
   163|  }
   164|  try {
   165|    const root = process.cwd();
   166|    const resolved = path.resolve(root, sourceFile);
   167|    if (!resolved.startsWith(root)) {
   168|      return null;
   169|    }
   170|    const contents = await readFile(resolved, 'utf8');
   171|    return contents.length > 12000 ? `${contents.slice(0, 12000)}\n… (truncated)` : contents;
   172|  } catch {
   173|    return null;
   174|  }
   175|}
