   181|/**
   182| * Drive a task to completion in the background, one block at a time. Safe to call
   183| * fire-and-forget. Re-reads task + blocks each loop so a pause/cancel issued via
   184| * the API takes effect between blocks, and so a crash mid-block resumes cleanly.
   185| */
   186|export async function driveTask(taskId: string, executor: IVXBlockExecutor = defaultBlockExecutor): Promise<void> {
   187|  if (activeRuns.has(taskId)) {
   188|    return;
   189|  }
   190|  activeRuns.add(taskId);
   191|  try {
   192|    let task = await getTask(taskId);
   193|    if (!task) {
   194|      return;
   195|    }
   196|    await updateTask(taskId, { status: 'running', error: null });
   197|
   198|    while (true) {
   199|      task = await getTask(taskId);
   200|      if (!task) {
   201|        return;
   202|      }
   203|      if (task.status === 'paused' || task.status === 'cancelled') {
   204|        await appendTaskEvent(taskId, { type: 'TASK_HALTED', blockId: null, detail: task.status });
   205|        return;
   206|      }
   207|
   208|      const blocks = await getTaskBlocks(taskId);
   209|      const block = findResumeBlock(blocks);
   210|
   211|      if (!block) {
   212|        // No runnable block left — settle the task status from the block roll-ups.
   213|        await finalizeTaskStatus(taskId);
   214|        return;
   215|      }
   216|
   217|      if (block.attempts >= MAX_ATTEMPTS_PER_BLOCK) {
   218|        await updateTaskBlock(taskId, block.id, {
   219|          status: 'FAILED',
   220|          error: `Exceeded ${MAX_ATTEMPTS_PER_BLOCK} attempts.`,
   221|          blocker: block.blocker ?? `Block failed after ${MAX_ATTEMPTS_PER_BLOCK} attempts.`,
   222|        });
   223|        continue;
   224|      }
   225|
   226|      await updateTaskBlock(taskId, block.id, {
   227|        status: 'RUNNING',
   228|        startedAt: block.startedAt ?? new Date().toISOString(),
   229|        attempts: block.attempts + 1,
   230|      });
   231|      await appendTaskEvent(taskId, { type: 'BLOCK_STARTED', blockId: block.id, detail: block.title });
   232|
   233|      let result: IVXBlockExecutionResult;
   234|      try {
   235|        result = await executor(block, task);
   236|      } catch (error) {
   237|        // A thrown executor is treated as a recoverable crash — persist details
   238|        // and let the loop resume this same block (until attempts are exhausted).
   239|        const message = error instanceof Error ? error.message : 'Executor crashed.';
   240|        await recordCrash(taskId, block.id, message);
   241|        await updateTaskBlock(taskId, block.id, { status: 'PENDING', error: message });
   242|        const after = await getTask(taskId);
   243|        if (!after || after.recoveryCount >= MAX_RECOVERIES) {
   244|          await updateTaskBlock(taskId, block.id, { status: 'FAILED', blocker: `Crash recovery cap reached: ${message}` });
   245|          await finalizeTaskStatus(taskId);
   246|          return;
   247|        }
   248|        continue;
   249|      }
   250|
   251|      const completedAt = ['COMPLETED', 'DEPLOYED', 'VERIFIED'].includes(result.status) ? new Date().toISOString() : null;
   252|      await updateTaskBlock(taskId, block.id, {
   253|        status: result.status,
   254|        codeChanges: result.codeChanges ?? block.codeChanges,
   255|        codeDiff: result.codeDiff ?? block.codeDiff,
   256|        validationCommand: result.validationCommand ?? block.validationCommand,
   257|        testResult: result.testResult ?? block.testResult,
   258|        commitHash: result.commitHash ?? block.commitHash,
   259|        deploymentStatus: result.deploymentStatus ?? block.deploymentStatus,
   260|        verification: result.verification ?? block.verification,
   261|        filesInvolved: result.filesInvolved ?? block.filesInvolved,
   262|        blocker: result.blocker ?? null,
   263|        error: result.error ?? null,
   264|        completedAt,
   265|      });
   266|
   267|      if (result.deploymentStatus) {
   268|        await updateTask(taskId, { deploymentStatus: result.deploymentStatus });
   269|      }
   270|
   271|      // Emit the real written code as a forensics event so the live coding stream
   272|      // can render the exact characters IVX produced for this block.
   273|      if (result.codeDiff && result.codeDiff.trim()) {
   274|        await appendTaskEvent(taskId, {
   275|          type: 'CODE_STREAM',
   276|          blockId: block.id,
   277|          detail: result.codeDiff.slice(0, 8000),
   278|        });
   279|      }
   280|
   281|      // BLOCKED / FAILED blocks do not stop the run — the loop advances to the
   282|      // next runnable block so independent work still completes. The final review
   283|      // surfaces every blocked/failed block to the owner.
   284|    }
   285|  } finally {
   286|    activeRuns.delete(taskId);
   287|  }
   288|}
