   290|/** Settle the overall task status from the authoritative block roll-ups. */
   291|async function finalizeTaskStatus(taskId: string): Promise<IVXTaskRecord | null> {
   292|  const blocks = await getTaskBlocks(taskId);
   293|  const anyFailed = blocks.some((block) => block.status === 'FAILED');
   294|  const anyBlocked = blocks.some((block) => block.status === 'BLOCKED');
   295|  const status: IVXTaskRecord['status'] = anyFailed ? 'failed' : anyBlocked ? 'blocked' : 'completed';
   296|  const settled = await updateTask(taskId, { status, completedAt: new Date().toISOString() });
   297|  await appendTaskEvent(taskId, { type: `TASK_${status.toUpperCase()}`, blockId: null, detail: `${blocks.length} blocks` });
   298|  return settled;
   299|}
   300|
   301|/** Persist crash details and bump the recovery counter. */
   302|export async function recordCrash(taskId: string, blockId: string | null, detail: string): Promise<void> {
   303|  const task = await getTask(taskId);
   304|  await updateTask(taskId, {
   305|    lastCrash: { at: new Date().toISOString(), detail, blockId },
   306|    recoveryCount: (task?.recoveryCount ?? 0) + 1,
   307|  });
   308|  await appendTaskEvent(taskId, { type: 'CRASH_RECORDED', blockId, detail });
   309|}
   310|
   311|/** Create a crash-safe task: copy the original exactly, split into blocks, start. */
   312|export async function startTask(
   313|  ownerCommand: string,
   314|  options: { autoStart?: boolean; executor?: IVXBlockExecutor } = {},
   315|): Promise<{ task: IVXTaskRecord; blocks: IVXTaskBlock[] }> {
   316|  const original = ownerCommand;
   317|  const planned = splitTaskIntoBlocks(original);
   318|  const { task, blocks } = await createTask({
   319|    ownerCommand: original,
   320|    originalTask: original,
   321|    blocks: planned.length > 0 ? planned : [{ title: 'Task', goal: original }],
   322|  });
   323|  console.log('[IVXTaskOrchestrator] TASK_CREATED', { taskId: task.id, totalBlocks: task.totalBlocks });
   324|  if (options.autoStart !== false) {
   325|    void driveTask(task.id, options.executor ?? defaultBlockExecutor);
   326|  }
   327|  return { task, blocks };
   328|}
   329|
   330|/**
   331| * Resume a task after a crash, pause, or process restart. Continues from the last
   332| * unfinished block — completed blocks are kept, the original task is preserved.
   333| */
   334|export async function resumeTask(
   335|  taskId: string,
   336|  executor: IVXBlockExecutor = defaultBlockExecutor,
   337|): Promise<IVXTaskRecord | null> {
   338|  const task = await getTask(taskId);
   339|  if (!task) {
   340|    return null;
   341|  }
   342|  if (isTerminalTaskStatus(task.status)) {
   343|    return task;
   344|  }
   345|  if (activeRuns.has(taskId)) {
   346|    return task;
   347|  }
   348|  const blocks = await getTaskBlocks(taskId);
   349|  const resumeBlock = findResumeBlock(blocks);
   350|  // A RUNNING block left over from a crash should be retried, not abandoned.
   351|  if (resumeBlock && resumeBlock.status === 'RUNNING') {
   352|    await updateTaskBlock(taskId, resumeBlock.id, { status: 'PENDING' });
   353|  }
   354|  await appendTaskEvent(taskId, {
   355|    type: 'TASK_RESUMED',
   356|    blockId: resumeBlock?.id ?? null,
   357|    detail: resumeBlock ? `from block ${resumeBlock.index + 1}` : 'no unfinished block',
   358|  });
   359|  const resumed = await updateTask(taskId, { status: 'running', error: null });
   360|  void driveTask(taskId, executor);
   361|  return resumed ?? task;
   362|}
   363|
   364|export async function pauseTask(taskId: string): Promise<IVXTaskRecord | null> {
   365|  const task = await getTask(taskId);
   366|  if (!task || isTerminalTaskStatus(task.status)) {
   367|    return task;
   368|  }
   369|  return await updateTask(taskId, { status: 'paused' });
   370|}
   371|
   372|export async function cancelTask(taskId: string): Promise<IVXTaskRecord | null> {
   373|  const task = await getTask(taskId);
   374|  if (!task) {
   375|    return null;
   376|  }
   377|  return await updateTask(taskId, { status: 'cancelled', completedAt: new Date().toISOString() });
   378|}
