   380|export type IVXTaskFinalReview = {
   381|  taskId: string;
   382|  originalTask: string;
   383|  status: IVXTaskRecord['status'];
   384|  totalBlocks: number;
   385|  completedBlocks: number;
   386|  failedBlocks: number;
   387|  blockedBlocks: number;
   388|  verifiedBlocks: number;
   389|  deployedBlocks: number;
   390|  filesChanged: string[];
   391|  commitHashes: string[];
   392|  deploymentStatus: string | null;
   393|  testsPassed: number;
   394|  remainingIssues: string[];
   395|  blocks: IVXTaskBlock[];
   396|};
   397|
   398|/** Assemble the end-to-end final owner report from durable block state. */
   399|export async function buildTaskFinalReview(taskId: string): Promise<IVXTaskFinalReview | null> {
   400|  const task = await getTask(taskId);
   401|  if (!task) {
   402|    return null;
   403|  }
   404|  const blocks = await getTaskBlocks(taskId);
   405|  const filesChanged = [...new Set(blocks.flatMap((block) => block.filesInvolved))].filter(Boolean);
   406|  const commitHashes = [...new Set(blocks.map((block) => block.commitHash).filter((hash): hash is string => Boolean(hash)))];
   407|  const remainingIssues = blocks
   408|    .filter((block) => block.status === 'FAILED' || block.status === 'BLOCKED')
   409|    .map((block) => `Block ${block.index + 1} (${block.title}) — ${block.status}: ${block.blocker ?? block.error ?? 'see logs'}`);
   410|  const testsPassed = blocks.filter((block) => (block.testResult ?? '').toLowerCase().startsWith('passed')).length;
   411|
   412|  return {
   413|    taskId: task.id,
   414|    originalTask: task.originalTask,
   415|    status: task.status,
   416|    totalBlocks: blocks.length,
   417|    completedBlocks: blocks.filter((block) => ['COMPLETED', 'DEPLOYED', 'VERIFIED'].includes(block.status)).length,
   418|    failedBlocks: blocks.filter((block) => block.status === 'FAILED').length,
   419|    blockedBlocks: blocks.filter((block) => block.status === 'BLOCKED').length,
   420|    verifiedBlocks: blocks.filter((block) => block.status === 'VERIFIED').length,
   421|    deployedBlocks: blocks.filter((block) => block.status === 'DEPLOYED' || block.status === 'VERIFIED').length,
   422|    filesChanged,
   423|    commitHashes,
   424|    deploymentStatus: task.deploymentStatus,
   425|    testsPassed,
   426|    remainingIssues,
   427|    blocks,
   428|  };
   429|}
