   431|/**
   432| * On boot, find tasks that were mid-flight (running) when the process died and
   433| * resume them from their durable cursor. Returns the ids it resumed.
   434| */
   435|export async function recoverInterruptedTasks(
   436|  listFn: () => Promise<IVXTaskRecord[]>,
   437|  executor: IVXBlockExecutor = defaultBlockExecutor,
   438|): Promise<string[]> {
   439|  const tasks = await listFn();
   440|  const resumed: string[] = [];
   441|  for (const task of tasks) {
   442|    if (task.status === 'running' && !activeRuns.has(task.id)) {
   443|      await recordCrash(task.id, task.currentBlockId, 'Process restart detected — resuming from durable cursor.');
   444|      await resumeTask(task.id, executor);
   445|      resumed.push(task.id);
   446|    }
   447|  }
   448|  return resumed;
