   215|/**
   216| * Prioritize the task queue by urgency and dependency resolution.
   217| * Critical tasks always come first. Then high/medium/low by creation time.
   218| * Tasks whose dependencies are unmet are pushed down.
   219| */
   220|function prioritizeQueue(tasks: OrchestratedTask[]): OrchestratedTask[] {
   221|  const priorityWeight: Record<OrchestratorPriority, number> = {
   222|    critical: 0,
   223|    high: 1,
   224|    medium: 2,
   225|    low: 3,
   226|    idle: 4,
   227|  };
   228|
   229|  const completedIds = new Set(
   230|    tasks.filter((t) => t.status === 'completed').map((t) => t.id),
   231|  );
   232|
   233|  return [...tasks].sort((a, b) => {
   234|    const aBlocked = a.dependencies.some((d) => !completedIds.has(d));
   235|    const bBlocked = b.dependencies.some((d) => !completedIds.has(d));
   236|    if (aBlocked && !bBlocked) return 1;
   237|    if (!aBlocked && bBlocked) return -1;
   238|    const pw = priorityWeight[a.priority] - priorityWeight[b.priority];
   239|    if (pw !== 0) return pw;
   240|    return new Date(a.createdAt).getTime() - new Date(b.createdAt).getTime();
   241|  });
   242|}
