   419|/**
   420| * Run one full orchestrator cycle:
   421| * 1. Detect blockers
   422| * 2. Recover recoverable tasks
   423| * 3. Prioritize queue
   424| * 4. Dispatch next ready task
   425| * 5. Update all subsystem health checks
   426| */
   427|export async function runOrchestratorCycle(): Promise<{
   428|  blockersFound: number;
   429|  recovered: number;
   430|  dispatched: number;
   431|  cycleCount: number;
   432|}> {
   433|  const state = await loadState();
   434|  state.cycleCount++;
   435|  state.lastCycleAt = new Date().toISOString();
   436|
   437|  // 1. Detect blockers
   438|  const blockers = await detectBlockers();
   439|  let recovered = 0;
   440|  if (state.autoRecoverEnabled) {
   441|    for (const blocker of blockers) {
   442|      const result = await recoverTask(blocker.id);
   443|      if (result && result.action !== 'escalate') recovered++;
   444|    }
   445|  }
   446|
   447|  // 2. Dispatch next ready task
   448|  const dispatched = await dispatchNextTask();
   449|
   450|  state.updatedAt = new Date().toISOString();
   451|  await persistState();
   452|
   453|  return {
   454|    blockersFound: blockers.length,
   455|    recovered,
   456|    dispatched: dispatched ? 1 : 0,
   457|    cycleCount: state.cycleCount,
   458|  };
