cd /home/user/rork-app/logs/audit/task-orchestrator && bun -e "
import { readdir, readFile } from 'node:fs/promises';
const dirs = await readdir('.');
const rows = [];
for (const d of dirs) {
  try {
    const task = JSON.parse(await readFile(d + '/task.json', 'utf8'));
    const blocks = JSON.parse(await readFile(d + '/blocks.json', 'utf8'));
    const commits = [...new Set(blocks.map(b => b.commitHash).filter(Boolean))];
    const deployed = blocks.filter(b => b.status === 'DEPLOYED' || b.status === 'VERIFIED').length;
    const completed = blocks.filter(b => b.status === 'COMPLETED').length;
    const blocked = blocks.filter(b => b.status === 'BLOCKED').map(b => (b.blocker ?? '').slice(0, 70));
    rows.push({ id: d.slice(5, 13), status: task.status, blocks: blocks.length, completed, deployed, commits, deployStatus: task.deploymentStatus, blocked });
  } catch {}
}
const byStatus = {};
for (const r of rows) byStatus[r.status] = (byStatus[r.status] ?? 0) + 1;
console.log('STATUS COUNTS:', JSON.stringify(byStatus));
console.log('COMPLETED tasks:');
for (const r of rows.filter(r => r.status === 'completed')) console.log(JSON.stringify(r));
console.log('BLOCKED tasks:');
for (const r of rows.filter(r => r.status === 'blocked')) console.log(JSON.stringify(r));
" 2>&1 | head -80

